import math


class Solution:
    def minimizedMaximum(self, n, quantities):
        def feasible(x):
            return sum(math.ceil(q / x) for q in quantities) <= n

        lo, hi = 1, max(quantities)
        while lo < hi:
            mid = lo + (hi - lo) // 2
            if feasible(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

