class Solution:
    def minimizedMaximum(self, n, quantities):
        lo, hi = 1, max(quantities)

        def feasible(x):
            stores = 0
            for q in quantities:
                stores += (q + x - 1) // x
            return stores <= n

        while lo < hi:
            mid = (lo + hi) // 2
            if feasible(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

