var minimizedMaximum = function(n, quantities) {
    let lo = 1, hi = Math.max(...quantities);
    const feasible = (x) => {
        let stores = 0;
        for (const q of quantities) {
            stores += Math.ceil(q / x);
        }
        return stores <= n;
    };
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (feasible(mid)) hi = mid; else lo = mid + 1;
    }
    return lo;
};
